2: // ║ COMPONENT: mk-dist-freshness-guard Regression Tests                     ║
3: // ╠══════════════════════════════════════════════════════════════════════════╣
4: // ║ PURPOSE: Pin the plugin export shape and warn-only freshness behavior    ║
5: // ║          against hermetic package fixtures.                              ║
6: // ╚══════════════════════════════════════════════════════════════════════════╝
7: 'use strict';
8: 
9: const assert = require('node:assert/strict');
10: const fs = require('node:fs');
11: const os = require('node:os');
12: const path = require('node:path');
13: const { pathToFileURL } = require('node:url');
14: 
15: function writeFileWithMtime(filePath, content, mtimeMs) {
16:   fs.mkdirSync(path.dirname(filePath), { recursive: true });
17:   fs.writeFileSync(filePath, content);
18:   const mtime = new Date(mtimeMs);
19:   fs.utimesSync(filePath, mtime, mtime);
20: }
21: 
22: function writeCodeModeFixture(dir, stale) {
23:   const packageDir = path.join(dir, '.opencode', 'skills', 'mcp-code-mode', 'mcp_server');
24:   const sourceMtime = Date.now();
25:   const distMtime = stale ? sourceMtime - 10_000 : sourceMtime + 10_000;
26: 
27:   writeFileWithMtime(path.join(packageDir, 'package.json'), '{"scripts":{"build":"tsc"}}\n', sourceMtime);
28:   writeFileWithMtime(path.join(packageDir, 'tsconfig.json'), '{"include":["index.ts"]}\n', sourceMtime);
29:   writeFileWithMtime(path.join(packageDir, 'index.ts'), 'export const value = 1;\n', sourceMtime);
30:   writeFileWithMtime(path.join(packageDir, 'dist', 'index.js'), 'export const value = 1;\n', distMtime);
31: }
32: 
33: async function loadPlugin() {
34:   const pluginUrl = pathToFileURL(path.join(__dirname, '..', 'mk-dist-freshness-guard.js')).href;
35:   return import(pluginUrl);
36: }
37: 
38: async function captureWarns(callback) {
39:   const warnings = [];
40:   const originalWarn = console.warn;
41:   const originalError = console.error;
42:   console.warn = (message) => warnings.push(String(message));
43:   console.error = (message) => warnings.push(String(message));
44:   try {
45:     await callback();
46:   } finally {
47:     console.warn = originalWarn;
48:     console.error = originalError;
49:   }
50:   return warnings;
51: }
52: 
53: async function main() {
54:   const pluginModule = await loadPlugin();
55:   assert.deepEqual(Object.keys(pluginModule), ['default']);
56:   assert.equal(typeof pluginModule.default, 'function');
57: 
58:   const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'mk-dist-freshness-guard-'));
59:   try {
60:     writeCodeModeFixture(tmpDir, true);
61:     const hooks = await pluginModule.default({ directory: tmpDir });
62:     const beforeHook = hooks['tool.execute.before'];
63:     const eventHook = hooks.event;
64:     assert.equal(typeof beforeHook, 'function');
65:     assert.equal(typeof eventHook, 'function');
66: 
67:     let warnings = await captureWarns(async () => {
68:       await beforeHook({ tool: 'read' }, { args: { command: 'validate.sh fixture' } });
69:       await beforeHook({ tool: 'bash' }, { args: { command: 'node scripts/safe.js' } });
70:     });
71:     assert.equal(warnings.length, 0, 'non-bash and unrelated bash commands must not warn');
72: 
73:     warnings = await captureWarns(async () => {
74:       await beforeHook({ tool: 'bash' }, { args: { command: 'bash .opencode/skills/system-spec-kit/scripts/spec/validate.sh fixture' } });
